// Loop over input items and add a new field called 'myNewField' to the JSON of each one
function agruparFluxo(fluxo) {
    let resultado = [];
    let i = 0;

    while (i < fluxo.length) {
        let item = fluxo[i];

        if (item.Comando === "ENVIO_MENSAGEM") {
            let subitens = [];
            let qtdSubitens = parseInt(item.Ação, 10) || 0;

            for (let j = 1; j <= qtdSubitens; j++) {
                if (i + j < fluxo.length) {
                    subitens.push(fluxo[i + j]);
                }
            }

            subitens = subitens.map(item => ({
                type: item.Comando === "BOTÃO_URL" ? "web_url" : "postback",
                url: item.Comando === "BOTÃO_URL" ? item["Ação"] : undefined,
                payload: item.Comando === "BOTÃO_RESPONDER" ? item["Ação"] : undefined,
                title: item.Valor
              })).map(obj => Object.fromEntries(Object.entries(obj).filter(([_, v]) => v !== undefined)));

            resultado.push({ ...item, Botões: subitens });
            i += qtdSubitens; // Pular os subitens processados
        } else {
            resultado.push(item);
        }
        i++;
    }

    return resultado;
}

for (const item of $input.all()) {
  item.json.fluxo = agruparFluxo(item.json.fluxo);
}

return $input.all();
